/* 
 算法名称： 枚举高位拼接 + 字符串查找
 关键技巧： 将 A 放在 B 的低位，枚举高位 x，判断 2B 是否含 A
 时间复杂度： O(K)，K=10^5
*/
#include <bits/stdc++.h>
using namespace std;
using ll = long long;
const int INF = 0x3f3f3f3f;
constexpr int MAX_X = 100000;         // x 枚举上限
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    if(!(cin >> s)) return 0;
    int len = (int)s.size();
    // 预计算 10^len
    int pow10 = 1;
    for(int i = 0; i < len; i++){
        pow10 *= 10;
    }
    // 将 A 转为整数
    int a = stoi(s);

    // 枚举高位 x
    for(int x = 0; x <= MAX_X; x++){
        // 构造 B = x*10^len + a
        ll B = ll(x) * pow10 + a;
        if(B > INT_MAX) break;           // 超出 int 范围，停止枚举
        // DEBUG: 当前尝试的 B
        // 计算 2B 并做子串检测
        ll TB = B << 1;                  // 2*B
        string tB = to_string(TB);
        // 如果 2B 的十进制表示中含有子串 s，则输出 B
        if(tB.find(s) != string::npos){
            cout << B;
            return 0;
        }
    }
    // 按题意保证至少有解，此处理论不会到达
    return 0;
}

